import{_ as e,c as s,a,o as n}from"./app-CEcM0piI.js";const l={};function r(d,i){return n(),s("div",null,i[0]||(i[0]=[a(`<h2 id="精灵图" tabindex="-1"><a class="header-anchor" href="#精灵图"><span>精灵图</span></a></h2><p>一个网页中往往会应用很多小的背景图像作为修饰，当网页中的图像过多时，服务器就会频繁地接收和发送请求图片，造成服务器请求压力过大，这将大大降低页面的加载速度。 因此，为了有效地减少服务器接收和发送请求的次数，提高页面的加载速度，出现了CSS精灵技术（也称CSS Sprites、CSS 雪碧）。</p><p><mark>核心原理：将网页中的一些小背景图像整合到一张大图中，这样服务器只需要一次请求就可以了。</mark></p><ol><li>精灵图主要针对于小的背景图片使用。</li><li>主要借助于背景位置来实现---background-position。</li><li>一般情况下精灵图都是负值。（千万注意网页中的坐标：x轴右边走是正值，左边走是负值，y轴同理。</li></ol><h2 id="字体图标" tabindex="-1"><a class="header-anchor" href="#字体图标"><span>字体图标</span></a></h2><p>精灵图是有诸多优点的，但是缺点很明显</p><ol><li>图片文件还是比较大的。</li><li>图片本身放大和缩小会失真</li><li>一旦图片制作完毕想要更换非常复杂。</li></ol><p>此时，有一种技术的出现很好的解决了以上问题，就是字体图标iconfont。 字体图标可以为前端工程师提供一种方便高效的图标使用方式，展示的是图标，本质属于字体。</p><p><strong>字体图标的优点</strong></p><ul><li>轻量级：一个图标字体要比一系列的图像要小。一旦字体加载了，图标就会马上渲染出来，减少了服务器请求</li><li>灵活性：本质其实是文字，可以很随意的改变颜色、产生阴影、透明效果、旋转等</li><li>兼容性：几乎支持所有的浏览器，请放心使用R</li></ul><p><strong>字体文件格式</strong></p><p>不同浏览器所支持的字体格式是不一样的，字体图标之所以兼容，就是因为包含了主流浏览器支持的字体文件。</p><ol><li>TureType(.ttf)格式.ttf字体是Windows和Mac的最常见的字体，支持这种字体的浏览器有lE9+、Firefox3.5+、Chrome4+、Safari3+、Opera10+、iOS Mobile、Safari4.2+ ;</li><li>WebOpenFontFormat(.woff)格式woff字体，支持这种字体的浏览器有lE9+、Firefox3.5+、Chrome6+、Safari3.6+、Opera11.1+ ;</li><li>Embedded Open Type(.eot)格式.eot字体是IE专用字体，支持这种字体的浏览器有IE4+；</li><li>SVG(.svg)格式.svg字体是基于SvVG字体渲染的一种格式，支持这种字体的浏览器有Chrome4+、Safari3.1+、Opera10.0+、iOS Mobile Safari3.2+ ;</li></ol><p>要使用字体图标需要在样式中引入对应的字体图标字体库 引入后还需要在要显示字体图标的标签内设置字体样式为对应引入的字体样式</p><p>如果工作中，原来的字体图标不够用了，我们需要添加新的字体图标到原来的字体文件中。把压缩包里面的selection.json从新上传，然后选中自己想要新的图标，从新下载压缩包，并替换原来的文件即可。</p><h2 id="界面样式" tabindex="-1"><a class="header-anchor" href="#界面样式"><span>界面样式</span></a></h2><h4 id="鼠标样式cursor" tabindex="-1"><a class="header-anchor" href="#鼠标样式cursor"><span>鼠标样式cursor</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{cursor:pointer;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>设置或检索在对象上移动的鼠标指针采用何种系统预定义的光标形状</p><ul><li>default : 小白(默认)</li><li>pointer : 小手</li><li>move : 移动</li><li>text : 文本</li><li>not-allowed : 禁止</li></ul><h4 id="轮廓线" tabindex="-1"><a class="header-anchor" href="#轮廓线"><span>轮廓线</span></a></h4><p>给表单添加<code>outline:0;</code>或者<code>outline:none;</code>样式之后，就可以去掉默认的蓝色边框。</p><h4 id="放置拖拽文本域resize" tabindex="-1"><a class="header-anchor" href="#放置拖拽文本域resize"><span>放置拖拽文本域resize</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>textarea{resize:none;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>文本域的开始标签和结束标签如果跨行的话在浏览器中的文本域开头会多一些空格</p><h2 id="vertical-align属性应用" tabindex="-1"><a class="header-anchor" href="#vertical-align属性应用"><span>vertical-align属性应用</span></a></h2><p>CSS的vertical-align属性使用场景：经常用于设置图片或者表单(行内块元素）和文字垂直对齐。 官方解释：用于设置一个元素的垂直对齐方式，但是它<strong>只针对于行内元素或者行内块元素有效</strong>。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vertical-align : baseline|top丨middle丨bottom</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>baseline : 默认。元素放置在父元素的基线上。</li><li>top : 把元素的顶端与行中最高元素的顶端对齐</li><li>middle : 把此元素放置在父元素的中部。</li><li>bottom : 把元素的顶端与行中最低的元素的顶端对齐。 ![[Clip_2024-09-29_15-49-01.png]]</li></ul><p><strong>解决图片底部默认空白缝隙问题</strong></p><p>图片底侧会有一个空白缝隙，原因是行内块元素会和文字的基线对齐。</p><p>主要解决方法有两种：</p><ol><li>给图片添加vertical-align:middle|toplbottom等。（提倡使用的）</li><li>把图片转换为块级元素display:block;</li></ol><h2 id="单行文本溢出显示省略号" tabindex="-1"><a class="header-anchor" href="#单行文本溢出显示省略号"><span>单行文本溢出显示省略号</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>/*1．先强制一行内显示文本*/</span></span>
<span class="line"><span>white-space: nowrap;    //默认 normal 自动换行</span></span>
<span class="line"><span>/*2．超出的部分隐藏*/</span></span>
<span class="line"><span>overflow: hidden;</span></span>
<span class="line"><span>/*3．文字用省略号替代超出的部分*/</span></span>
<span class="line"><span>text-overflow: ellipsis;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="多行文本溢出显示省略号" tabindex="-1"><a class="header-anchor" href="#多行文本溢出显示省略号"><span>多行文本溢出显示省略号</span></a></h3><p>多行文本溢出显示省略号，有较大兼容性问题，适合于webKit浏览器或移动端（移动端大部分是webkit内核)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>overflow: hidden;</span></span>
<span class="line"><span>text-overflow:ellipsis;</span></span>
<span class="line"><span>/*弹性伸缩盒子模型显示大*/</span></span>
<span class="line"><span>display: -webkit-box;</span></span>
<span class="line"><span>/*限制在一个块元素显示的文本的行数*/</span></span>
<span class="line"><span>-webkit-line-clamp: 2;</span></span>
<span class="line"><span>/*1设置或检索伸缩盒对象的子元素的排列方式*/</span></span>
<span class="line"><span>-webkit-box-orient:vertical;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="布局技巧" tabindex="-1"><a class="header-anchor" href="#布局技巧"><span>布局技巧</span></a></h2><h3 id="margin负值的使用" tabindex="-1"><a class="header-anchor" href="#margin负值的使用"><span>margin负值的使用</span></a></h3><p>当对一个盒子进行浮动设置的时候,多个盒子排序后他们的边框会像表格中的那样连着,即两个盒子相接触的边框比设置的边框值大,这是因为把两个边框的宽度都算进去了,此时可以使用margin设置为负值使盒子相接触的部分重叠 原理是在渲染的时候第一个盒子先靠左浮动,然后边框负值再减去,后面的盒子在靠左浮动的时候紧贴着前一个盒子边框,然后再取负值这样就会使边框重叠</p><p>但这样也会使边框样式受到影响 比如当光标进入到盒子内部时边框变色,如果使用负值margin就会导致被压住的边框看不到变色 此时可以:</p><ol><li>让每个盒子margin往左侧移动-1px正好压住相邻盒子边框</li><li>鼠标经过某个盒子的时候，提高当前盒子的层级即可（如果没有有定位，则加相对定位（保留位置），如果有定位，则加z-index.(绝对定位不占有位置因此不能使用)</li></ol><p>但如果盒子内部有绝对定位的话盒子就不能设置为相对定位了,可以设置<code>z-index</code>属性提高等级可以实现</p>`,44)]))}const p=e(l,[["render",r]]),h=JSON.parse('{"path":"/front/css/8/","title":"8 页面技巧","lang":"zh-CN","frontmatter":{"title":"8 页面技巧","createTime":"2025/06/18 21:11:24","permalink":"/front/css/8/"},"readingTime":{"minutes":5.73,"words":1719},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/8 页面技巧.md","headers":[]}');export{p as comp,h as data};
